import React, { useState, useEffect, useRef, useCallback } from 'react'
import useData, { pageLimit } from './data';
import { useTableContext } from './Provider';

function InfiniteScroll({ children }) {
    const [page, setPage] = useState(0)
    const { loading, error, tableData, total } = useData(page);
    const { setTableData, searchedData } = useTableContext()

    const observerRef = useRef(null)
    const [isLoading, setIsLoading] = useState(false)
    const [hasMore, setHasMore] = useState(false)

    // ✅ SAME: push API data to context
    useEffect(() => {
        if (tableData) {
            setTableData(tableData)
        }
    }, [tableData])

    // ✅ SAME: compute hasMore
    useEffect(() => {
        if (searchedData) {
            setHasMore(searchedData.length < total)
        }
    }, [searchedData, total])

    // ✅ FIXED: proper observer logic (based on GOOD example)
    const lastItemRef = useCallback((node) => {
        if (!node || !hasMore || isLoading) return

        if (observerRef.current) {
            observerRef.current.disconnect()
        }

        let isSubscribed = true

        observerRef.current = new IntersectionObserver(([entry]) => {
            if (entry.isIntersecting && hasMore && !isLoading) {
                setIsLoading(true)

                // Prevent multiple triggers
                observerRef.current.disconnect()

                // Trigger next page
                setPage(prev => prev + 1)

                // Small delay to allow new data to flow
                Promise.resolve().then(() => {
                    if (isSubscribed) {
                        setIsLoading(false)
                    }
                })
            }
        })

        observerRef.current.observe(node)

        return () => {
            isSubscribed = false
            if (observerRef.current) {
                observerRef.current.disconnect()
            }
        }
    }, [hasMore, isLoading])

    return (
        <>
            {children}

            {/* ✅ sentinel instead of custom hook */}
            <div ref={lastItemRef}>
                {isLoading && "...Loading"}
            </div>
        </>
    )
}

export default InfiniteScroll
